	}
	if len(m.shared) != 2 {
		t.Fatalf("shared sockets after add = %d, want 2", len(m.shared))
	}
	sharedB := m.shared[1]
	if sharedB.name != "shared-b" {
		t.Fatalf("new shared socket name = %q, want %q", sharedB.name, "shared-b")
	}

	for _, tc := range []struct {
